SELECT COUNT(*) AS journal_count
FROM journals
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Cybernetics');

SELECT journal_impact_factor
FROM journal_metrics
WHERE journal_id = 0;

SELECT SUM(article_count) AS total_articles
FROM journal_metrics
WHERE journal_id = 0;

SELECT MAX(journal_impact_factor) AS highest_impact_factor
FROM journal_metrics
WHERE year_id = 0;

SELECT COUNT(*) AS total_journals
FROM journals
WHERE publisher_id = (SELECT publisher_id FROM publishers WHERE publisher_name = 'Example Publishing House');

SELECT full_title
FROM journals
ORDER BY full_title;

SELECT AVG(journal_impact_factor) AS average_impact_factor
FROM journal_metrics
WHERE year_id = (SELECT year_id FROM years WHERE year_name = '2023');
